import React, { useState, useEffect } from 'react';
import api from '../../services/api';
import FilterBox from './FilterBox';
import JobCard from '../../components/jobs/JobCard';

// IMPORT SESUAI STRUKTUR TREE ANDA
import ApplyJobForm from '../lamaran/ApplyJobForm';
import FavoriteService from '../lamaran/FavoriteService';

const JobListContainer = ({ appTheme }) => {
    const isDark = appTheme === 'dark';

    // Contoh data jobs (pastikan ini nanti diisi dari API)
    const [jobs] = useState([
        { id: 1, title: 'Fullstack Developer', company: 'PasukanYerusSolo', location: 'Solo (Remote)', salary: 'Rp 8.000.000', type: 'Full-time', desc: 'Bertanggung jawab dalam membangun dan mengelola arsitektur web menggunakan React JS, Express JS, dan PHP Laravel.' },
        { id: 2, title: 'React Frontend Engineer', company: 'TechEase Indonesia', location: 'Jakarta', salary: 'Rp 12.000.000', type: 'Remote', desc: 'Fokus pada pengembangan antarmuka pengguna yang interaktif dan performan.' }
    ]);

    const [searchTerm, setSearchTerm] = useState('');
    const [selectedType, setSelectedType] = useState('Semua');
    const [selectedJob, setSelectedJob] = useState(jobs[0]);
    const [isMobile, setIsMobile] = useState(window.innerWidth <= 768);
    const [showApplyForm, setShowApplyForm] = useState(false);

    const colors = {
        cardBg: isDark ? '#120b06' : '#ffffff',
        border: isDark ? '1px solid #22140a' : '1px solid #eaddd3',
        textMain: isDark ? '#fef3c7' : '#291107',
        textMuted: isDark ? '#9e8476' : '#6b7280',
        accent: '#ea580c',
        sectionBg: isDark ? '#110a05' : '#fcfaf7',
        sectionBorder: isDark ? '1px solid #291a0e' : '1px solid #efe5dc'
    };

    const handleInisiasiLamaran = () => {
        if (!localStorage.getItem('token')) return alert('Silahkan login terlebih dahulu.');
        setShowApplyForm(true);
    };

    const filteredJobs = jobs.filter(job => {
        const query = (searchTerm || '').toLowerCase().trim();
        return (!query || job.title.toLowerCase().includes(query)) && (selectedType === 'Semua' || job.type === selectedType);
    });

    return (
        <div style={{ display: 'flex', flexDirection: 'column', gap: '20px', width: '100%' }}>
            <FilterBox appTheme={appTheme} onSearchChange={setSearchTerm} onTypeChange={setSelectedType} selectedType={selectedType} />

            <div style={{ display: 'flex', flexDirection: isMobile ? 'column' : 'row', gap: '24px' }}>
                <div style={{ flex: 1 }}>
                    {filteredJobs.map((job) => (
                        <div key={job.id} onClick={() => setSelectedJob(job)} style={{ cursor: 'pointer' }}>
                            <JobCard job={job} appTheme={appTheme} />
                        </div>
                    ))}
                </div>

                {!isMobile && selectedJob && (
                    <div style={{ width: '380px', background: colors.cardBg, border: colors.border, borderRadius: '16px', padding: '24px' }}>
                        {/* HEADER DETAIL */}
                        <span style={{ background: '#ffedd5', color: colors.accent, fontSize: '11px', fontWeight: '800', padding: '4px 10px', borderRadius: '20px' }}>{selectedJob.type}</span>
                        <h3 style={{ color: colors.textMain, margin: '12px 0 4px 0' }}>{selectedJob.title}</h3>
                        <p style={{ color: colors.accent, fontWeight: '700', fontSize: '14px', margin: '0 0 16px 0' }}>{selectedJob.company}</p>

                        {/* INFO LOKASI & GAJI */}
                        <div style={{ fontSize: '13px', color: colors.textMuted, marginBottom: '16px' }}>
                            <p><strong>Lokasi:</strong> {selectedJob.location}</p>
                            <p><strong>Gaji:</strong> {selectedJob.salary}</p>
                        </div>

                        {/* DESKRIPSI */}
                        <div style={{ background: isDark ? '#0d0703' : '#f9fafb', padding: '14px', borderRadius: '12px', border: colors.border, marginBottom: '20px' }}>
                            <p style={{ fontWeight: '700', color: colors.textMain, fontSize: '13px' }}>Deskripsi Pekerjaan:</p>
                            <p style={{ color: colors.textMuted, fontSize: '13px', lineHeight: '1.6' }}>{selectedJob.desc}</p>
                        </div>

                        {!showApplyForm ? (
                            <div style={{ display: 'flex', flexDirection: 'column', gap: '8px' }}>
                                <button style={{ padding: '14px', background: 'linear-gradient(135deg, #ea580c 0%, #f59e0b 100%)', color: 'white', border: 'none', borderRadius: '12px', fontWeight: '800', cursor: 'pointer' }} onClick={handleInisiasiLamaran}>
                                    Kirim Lamaran Sekarang
                                </button>
                                <FavoriteService jobId={selectedJob.id} appTheme={appTheme} />
                            </div>
                        ) : (
                            <div style={{ background: colors.sectionBg, padding: '16px', borderRadius: '14px', border: colors.sectionBorder }}>
                                <ApplyJobForm jobId={selectedJob.id} appTheme={appTheme} onFormSuccess={() => setShowApplyForm(false)} />
                                <button onClick={() => setShowApplyForm(false)} style={{ width: '100%', background: 'transparent', border: 'none', color: colors.textMuted, marginTop: '10px', cursor: 'pointer' }}>Batal</button>
                            </div>
                        )}
                    </div>
                )}
            </div>
        </div>
    );
};

export default JobListContainer;
